import { MakeLogicType, actions, kea, path, reducers } from 'kea'

import { ExperimentTemplate } from './constants'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface experimentTemplateModalLogicValues {
    isModalOpen: boolean
    template: ExperimentTemplate | null
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface experimentTemplateModalLogicActions {
    closeTemplateModal: () => {
        value: true
    }
    openTemplateModal: (template: ExperimentTemplate) => {
        template: ExperimentTemplate
    }
}

export type experimentTemplateModalLogicType = MakeLogicType<
    experimentTemplateModalLogicValues,
    experimentTemplateModalLogicActions
>

export const experimentTemplateModalLogic = kea<experimentTemplateModalLogicType>([
    path(['scenes', 'experiments', 'ExperimentForm', 'ExperimentTemplates', 'experimentTemplateModalLogic']),

    actions({
        openTemplateModal: (template: ExperimentTemplate) => ({ template }),
        closeTemplateModal: true,
    }),

    reducers({
        isModalOpen: [
            false,
            {
                openTemplateModal: () => true,
                closeTemplateModal: () => false,
            },
        ],
        template: [
            null as ExperimentTemplate | null,
            {
                openTemplateModal: (_, { template }) => template,
                closeTemplateModal: () => null,
            },
        ],
    }),
])
